<?php require __DIR__ . "/vendor/autoload.php"; $app = require_once __DIR__ . "/bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $year = 2026; $start = \Carbon\Carbon::parse("2026-03-10")->startOfDay(); $end = \Carbon\Carbon::parse("2026-03-23")->endOfDay(); $rows = \App\Models\ZakatTransaction::valid()->forPeriodOrYear(null, $year)->where(\Illuminate\Support\Facades\DB::raw("COALESCE(waktu_terima, created_at)"), ">=", $start)->where(\Illuminate\Support\Facades\DB::raw("COALESCE(waktu_terima, created_at)"), "<=", $end)->select(\Illuminate\Support\Facades\DB::raw("DATE(COALESCE(waktu_terima, created_at)) as day"), \Illuminate\Support\Facades\DB::raw("COALESCE(SUM(nominal_uang), 0) as total_uang"))->groupBy("day")->get(); echo json_encode($rows);
